css:
.ir-ad-header {
  margin-bottom: 16px;
}

.ir-ad-meta-table {
  width: 100%;
  border-collapse: separate;
  border-spacing: 0;
  border: 1px solid #333;
  border-radius: 8px;
  overflow: hidden;
}

.ir-ad-meta-table td {
  padding: 8px 12px;
  border-right: 1px solid #333;
  vertical-align: top;
  width: 50%;
}

.ir-ad-meta-table td:last-child {
  border-right: none;
}

.ir-ad-meta-table b {
  display: block;
  font-size: 9pt;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  margin-bottom: 3px;
  color: #555;
}

.ir-ad-columns {
  display: flex;
  gap: 24px;
  margin-top: 18px;
  align-items: flex-start;
}

.ir-ad-col {
  flex: 1;
  min-width: 0;
}

.ir-ad-col p {
  margin: 0 0 12px;
  font-size: 10pt;
  line-height: 1.4;
}

.ir-ad-heading {
  margin: 16px 0 10px;
  font-size: 12pt;
  font-weight: 700;
  border-bottom: 1px solid #b40000;
  padding-bottom: 4px;
  page-break-after: avoid;
}

.ir-ad-position-heading {
  margin: 10px 0 16px;
  font-size: 18pt;
  font-weight: 800;
  text-align: center;
}

.ir-ad-intro {
  margin: 0 0 6px;
  font-size: 10pt;
}

.ir-ad-list {
  margin: 0 0 12px;
  padding-left: 18px;
  font-size: 10pt;
}

.ir-ad-closing {
  margin-top: 16px;
  font-size: 10pt;
}

.ir-ad-closing b {
  display: block;
  margin-bottom: 3px;
}

@page {
  margin: 20mm 15mm 25mm 15mm;
  @bottom-right {
    content: "Page " counter(page) " of " counter(pages);
    font-size: 10pt;
    color: #999;
  }
}
